1	import express from 'express';
2	import cors from 'cors';
3	import { fileURLToPath } from 'node:url';
4	import { resolve, dirname, join } from 'node:path';
5	import commentsRouter from './api/comments.js';
6	import { initWs } from './ws/broadcaster.js';
7	
8	const __dirname = dirname(fileURLToPath(import.meta.url));
9	
10	function createApp() {
11	  const app = express();
12	  const isProduction = process.env.NODE_ENV === 'production';
13	
14	  // ── Middleware ────────────────────────────────────────────────────────────
15	  // NOTE: origin:'*' + credentials:true is invalid per CORS spec (browsers reject it).
16	  // Use origin:true (reflect request Origin) in dev so credentials can coexist if needed.
17	  app.use(cors({
18	    origin: isProduction ? false : true, // 'true' reflects the request's Origin header
19	    credentials: true,
20	  }));
21	  app.use(express.json());
22	
23	  // ── API Routes ────────────────────────────────────────────────────────────
24	  app.use('/api', commentsRouter);
25	
26	  // ── Routes ────────────────────────────────────────────────────────────────
27	  app.get('/health', (_req, res) => res.json({ ok: true }));
28	
29	  // Dev/test-only routes (not in production)
30	  if (!isProduction) {
31	    app.post('/dev/echo', (req, res) => res.json(req.body));
32	    app.get('/dev/error', (req, res, next) => {
33	      const err = new Error('Test error');
34	      err.status = req.query.status ? parseInt(req.query.status, 10) : 500;
35	      next(err);
36	    });
37	  }
38	
39	  // ── Static files (production) ─────────────────────────────────────────────
40	  if (isProduction) {
41	    const distPath = join(__dirname, '..', 'client', 'dist');
42	    app.use(express.static(distPath));
43	    app.get('*', (_req, res) =>
44	      res.sendFile(join(distPath, 'index.html'))
45	    );
46	  }
47	
48	  // ── 404 handler ───────────────────────────────────────────────────────────
49	  app.use((_req, res) => res.status(404).json({ error: 'Not Found' }));
50	
51	  // ── Error handler ─────────────────────────────────────────────────────────
52	  // eslint-disable-next-line no-unused-vars
53	  app.use((err, _req, res, _next) => {
54	    const status = err.status || err.statusCode || 500;
55	    res.status(status).json({ error: err.message || 'Internal Server Error' });
56	  });
57	
58	  return app;
59	}
60	
61	// Start when run as the entry point
62	// resolve() normalises relative paths before comparing
63	if (resolve(process.argv[1]) === fileURLToPath(import.meta.url)) {
64	  const app = createApp();
65	  const PORT = process.env.PORT || 3001;
66	  const server = app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
67	  initWs(server);
68	}
69	
70	export { createApp };
71

1	import { Router } from 'express';
2	import { createComment, ForeignKeyError } from '../db/queries.js';
3	
4	const router = Router();
5	
6	router.post('/cards/:id/comments', (req, res, next) => {
7	  const { author, content } = req.body ?? {};
8	
9	  if (!author || !content) {
10	    return res.status(400).json({ error: 'author and content are required' });
11	  }
12	
13	  try {
14	    const comment = createComment(req.params.id, { author, content });
15	    return res.status(201).json(comment);
16	  } catch (err) {
17	    if (err instanceof ForeignKeyError) {
18	      return res.status(404).json({ error: err.message });
19	    }
20	    next(err); // passes to Express error handler → 500
21	  }
22	});
23	
24	export default router;
